"""Accessible public sample UI for CivicHR."""


def render_public_lookup_page() -> str:
    return """<!doctype html>
<html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1"><title>CivicHR - HR policy support</title><style>:root{--ink:#241b18;--red:#7a2e2e;--rose:#fae7df;--gold:#bf8f35;--paper:#fffaf0}body{margin:0;font-family:"Aptos","Segoe UI",sans-serif;color:var(--ink);background:radial-gradient(circle at 20% 0,#fae7df,transparent 32rem),linear-gradient(135deg,#fff7f1,var(--paper))}header,main,footer{width:min(1080px,calc(100% - 32px));margin:auto}header{padding:52px 0 20px}.eyebrow{text-transform:uppercase;letter-spacing:.14em;color:var(--red);font-weight:900}h1{font:800 clamp(2.35rem,7vw,5.2rem)/.95 Georgia,serif;margin:.1em 0}.lede{font-size:1.2rem;line-height:1.6;max-width:850px}.grid{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:18px}.card{background:rgba(255,255,255,.92);border:1px solid #e2b9aa;border-radius:24px;padding:24px;box-shadow:0 18px 36px #3b2b2618}.badge{display:inline-block;background:var(--red);color:white;padding:.5rem .85rem;border-radius:999px;font-weight:900}code{background:var(--rose);padding:.1rem .35rem;border-radius:.35rem}:focus-visible{outline:4px solid var(--gold);outline-offset:3px}@media(max-width:720px){.grid{grid-template-columns:1fr}header{padding-top:34px}}</style></head><body><header><p class="eyebrow">CivicSuite / CivicHR</p><h1>HR policy support without becoming an HRIS.</h1><p class="lede">CivicHR v0.1.0 helps staff prepare personnel-policy lookup outlines, job-description drafts, onboarding packet checklists, and HR source-readiness reviews.</p><p><span class="badge">Shipping v0.1.0</span></p></header><main><section class="grid" aria-label="CivicHR release status"><article class="card"><h2>What ships</h2><ul><li>Personnel-policy lookup outlines.</li><li>Job-description draft scaffolds.</li><li>Handbook summaries, classification lookups, and training checklists.</li><li>Onboarding packet and intake template checklists.</li><li>HR source-readiness review.</li><li>Sensitive-topic preflight.</li></ul></article><article class="card"><h2>Human approval required</h2><p>HR and counsel review remain mandatory for employment-law, accommodation, discipline, compensation, and personnel-file topics.</p></article><article class="card"><h2>Boundaries</h2><p>No HRIS, payroll, benefits administration, personnel-file storage, employment-law advice, autonomous publication, or live LLM calls ship in v0.1.0.</p></article><article class="card"><h2>Dependency</h2><p>Pinned to <code>civiccore==0.2.0</code>. CivicCore remains dependency-only; it never imports from CivicHR.</p></article></section></main><footer><p>Apache 2.0 code. CC BY 4.0 docs. Run locally by the city.</p></footer></body></html>"""
